// // This module selects between two 4-bit inputs based on a 1-bit select signal.
// When sel is 1, Y outputs the value of A; when sel is 0, Y outputs the value of B.
module mux_2to1(
    input sel,
    input [3:0] A,
    input [3:0] B,
    output reg [3:0] Y
);

always @(*) begin
    if (sel)
        Y = B;
    else
        Y = A;
end

endmodule
